INSERT INTO `assignment` VALUES (1, '1', 'www', '1', '2026-06-25 16:22:56', 100.00, 'PUBLISHED', 1, '2026-06-15 10:23:28', '2026-06-25 16:22:01');
INSERT INTO `assignment` VALUES (2, '样例-智能体方案设计能力考核', '围绕一个真实教学或科研场景，设计一个具备角色分工、工具调用和记忆管理能力的智能体方案，并提交方案文档与演示视频。', '智能体', '2026-06-22 15:03:28', 100.00, 'PUBLISHED', 1, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment` VALUES (3, '样例-Prompt Engineering 实战能力考核', '完成提示词结构化设计、对比实验与效果复盘，重点考察系统提示、用户输入、约束条件和输出格式控制能力。', '智能体', '2026-06-18 15:03:28', 100.00, 'PUBLISHED', 1, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment` VALUES (4, '样例-Code Sandbox 调试能力考核', '在沙箱环境中复现一段代码生成任务，记录调试过程、错误定位方法和最终可运行结果。', '智能体', '2026-06-14 15:03:28', 100.00, 'PUBLISHED', 1, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment` VALUES (5, '样例-课程综合展示能力考核', '用于后台预览的草稿考核：要求学生综合展示一个完整学习成果，包括问题定义、技术路线、实验结果和反思。', '综合考核', '2026-06-29 15:03:28', 100.00, 'DRAFT', 1, '2026-06-15 15:03:28', '2026-06-15 17:20:21');
INSERT INTO `assignment` VALUES (12, '样例-智能体项目综合能力考核（完整题面预览）', '请围绕“研究生学习辅助智能体”完成一次完整方案设计与原型说明。考核重点不是附件数量，而是你能否清晰描述业务场景、智能体分工、工具调用流程、风险控制与最终交付物。提交时可以直接填写文字答案，也可以补充上传方案文档、流程图或演示视频。', '智能体', '2026-06-30 23:59:00', 100.00, 'PUBLISHED', 1, '2026-06-16 10:53:19', '2026-06-16 10:53:54');
