INSERT INTO `assignment_material` VALUES (4, 1, 'VIDEO', '2026-06-19_152302_747.mp4', '2026-06-19_152302_747.mp4', 'assignment-1/VIDEO-8bb2457d-f2b5-4e51-85db-bbbfe941f576.mp4', 'video/mp4', 1031538, 4, '2026-06-19 15:23:23');
INSERT INTO `assignment_question` VALUES (4, 2, '场景与目标定义', '说明智能体服务的对象、业务流程、核心目标和成功标准。要求描述清楚输入、输出和约束条件。', 30.00, 1, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment_question` VALUES (5, 2, '智能体架构设计', '画出或描述角色分工、任务拆解、工具调用、记忆机制和异常处理流程。', 40.00, 2, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment_question` VALUES (6, 2, '演示与反思', '提交一段演示视频，并说明当前方案的不足、风险和后续优化方向。', 30.00, 3, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment_question` VALUES (7, 3, '提示词拆解', '选取一个大模型任务，将提示词拆解为角色、目标、上下文、约束、输出格式五个部分。', 35.00, 1, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment_question` VALUES (8, 3, '对比实验', '至少设计两组提示词版本，比较输出质量、稳定性和可复用性。', 40.00, 2, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment_question` VALUES (9, 3, '复盘报告', '总结提示词调优过程中的有效策略和失败案例。', 25.00, 3, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment_question` VALUES (10, 4, '任务复现', '在沙箱环境中复现代码生成任务，并截图或记录运行结果。', 30.00, 1, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment_question` VALUES (11, 4, '错误定位', '列出至少两个出现过的错误，说明定位思路、修改方法和验证结果。', 40.00, 2, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment_question` VALUES (12, 4, '最终交付', '提交可运行代码、运行说明和结果说明。', 30.00, 3, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment_question` VALUES (13, 5, '综合展示材料', '整理课程学习成果，形成一份结构完整的汇报文档。', 50.00, 1, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment_question` VALUES (14, 5, '展示视频', '录制 3-5 分钟展示视频，说明技术路线和关键成果。', 50.00, 2, '2026-06-15 15:03:28', '2026-06-15 15:03:28');
INSERT INTO `assignment_question` VALUES (26, 12, '一、需求场景与用户目标分析', '选择一个具体的研究生学习或科研协作场景，例如文献精读、实验复现、论文选题、组会汇报准备等。请说明：\n1. 目标用户是谁，当前流程中最耗时或最容易出错的环节是什么；\n2. 智能体需要接收哪些输入，输出哪些结果；\n3. 判断方案是否有效的标准是什么，至少给出 3 个可观察指标。', 25.00, 1, '2026-06-16 10:53:53', '2026-06-16 10:53:53');
INSERT INTO `assignment_question` VALUES (27, 12, '二、智能体角色分工与工作流设计', '设计一个不少于 3 个角色的多智能体协作流程，例如规划者、检索者、执行者、评审者、记忆管理员等。请描述：\n1. 每个角色的职责边界；\n2. 角色之间如何传递上下文和中间结果；\n3. 当某一步输出质量不达标时，系统如何重试、回退或交给人工确认。可以用文字、表格或流程图说明。', 30.00, 2, '2026-06-16 10:53:53', '2026-06-16 10:53:53');
INSERT INTO `assignment_question` VALUES (28, 12, '三、工具调用、记忆机制与安全约束', '结合你的场景，说明智能体需要调用哪些外部工具或资源，例如搜索、代码执行、数据库、文件解析、Notebook、API 服务等。请重点说明：\n1. 哪些信息适合进入短期上下文，哪些信息适合沉淀为长期记忆；\n2. 如何避免泄露 API Key、学生隐私、未公开实验数据等敏感信息；\n3. 工具调用失败、网络不可用或依赖缺失时，系统应如何给出可理解的反馈。', 25.00, 3, '2026-06-16 10:53:53', '2026-06-16 10:53:53');
INSERT INTO `assignment_question` VALUES (29, 12, '四、交付物与复盘说明', '提交一份最终方案说明，可以包含文字答案、方案文档、截图或演示视频。请在答案中补充：\n1. 你的方案相比人工完成有哪些效率或质量提升；\n2. 当前方案最主要的不足或风险是什么；\n3. 如果继续迭代，你会优先改进哪一个模块，为什么。', 20.00, 4, '2026-06-16 10:53:53', '2026-06-16 10:53:53');
