INSERT INTO `learning_item` VALUES (1, 834729, '凯撒密码 (Caesar Cipher)', '介绍凯撒密码的原理、历史及实现方法。', '古典密码学', '中等', '60分钟', '基础代数、Python编程', '\"理解并实现凯撒密码\"', '[{\"title\": \"原理简单\", \"description\": \"单字母位移加密\"}, {\"title\": \"历史悠久\", \"description\": \"古罗马军事通信\"}, {\"title\": \"易于实现\", \"description\": \"适合编程教学\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (2, 873492, '仿射密码 (Affine Cipher)', '单表替换密码，基于线性变换加密，是凯撒密码的推广，依赖模运算与乘法逆元', '古典密码学', '中等', '2小时', '基础数论（模运算、最大公约数）、简单密码学概念', '\"掌握仿射密码原理与应用\"', '[{\"title\": \"线性变换\", \"description\": \"乘法缩放结合加法平移\"}, {\"title\": \"密钥约束\", \"description\": \"乘子需与字母表互质\"}, {\"title\": \"代数基础\", \"description\": \"依赖模逆元与同余运算\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (3, 739265, '维吉尼亚密码 (Vigenère Cipher)', '多表替换密码，以关键词控制移位，曾被认为不可破解，可通过Kasiski检验破解', '古典密码学', '简单', '1.5小时', '凯撒密码基础、字母频率分析概念', '\"掌握维吉尼亚密码加解密与破解\"', '[{\"title\": \"多表替换\", \"description\": \"关键词控制多组移位规则\"}, {\"title\": \"密钥循环\", \"description\": \"密钥重复使用与明文等长\"}, {\"title\": \"Kasiski破解\", \"description\": \"通过重复子串推测密钥长度\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (4, 847391, '普莱费尔密码 (Playfair Cipher)', '双字母替换密码，基于5×5密钥方阵，按特定规则加密，一战中英军曾使用', '古典密码学', '中等', '2小时', '基础密码学概念、矩阵坐标认知', '\"掌握普莱费尔密码加解密\"', '[{\"title\": \"双字母替换\", \"description\": \"以字母对为加密单元\"}, {\"title\": \"5×5方阵\", \"description\": \"密钥构建核心矩阵结构\"}, {\"title\": \"规则加密\", \"description\": \"同行同列矩形三类规则\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (5, 928574, '普莱费尔密码 (Playfair Cipher)', '基于5×5密钥方阵的双字母替换密码，按三类规则加密，一战英军曾广泛使用', '古典密码学', '中等', '2小时', '基础字母映射、矩阵坐标概念、模运算基础', '\"掌握普莱费尔密码完整应用\"', '[{\"title\": \"双字母替换\", \"description\": \"以二元组为核心加密单元\"}, {\"title\": \"方阵密钥\", \"description\": \"5×5矩阵承载密钥信息\"}, {\"title\": \"规则驱动\", \"description\": \"同行同列矩形三类逻辑\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (6, 672945, '波利比奥斯方阵密码 (Polybios Square Cipher)', '基于5×5方阵的字母-数字映射密码，是多类经典密码的理论基础', '古典密码学', '简单', '1小时', '基础字母识别、矩阵坐标概念', '\"掌握波利比奥斯密码加解密\"', '[{\"title\": \"字母数字\", \"description\": \"字母与数字对一一映射\"}, {\"title\": \"单字母替换\", \"description\": \"单个字母对应单个数字对\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (7, 893456, '栅栏密码 (Rail Fence Cipher)', '基于Z字形排列的换位密码，通过调整字母顺序加密，是经典教学案例', '古典密码学', '简单', '1小时', '基础字符串操作、简单周期函数概念', '\"掌握栅栏密码加解密与原理\"', '[{\"title\": \"换位加密\", \"description\": \"不改字母仅调整顺序\"}, {\"title\": \"Z字排列\", \"description\": \"栅栏状交错排列字母\"}, {\"title\": \"栅栏数可调\", \"description\": \"栅栏数量决定加密复杂度\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (8, 734892, '列置换密码 (Columnar Transposition Cipher)', '按行写矩阵、按密钥列序读的换位密码，一战二战曾军事应用', '古典密码学', '中等', '1.5小时', '基础矩阵概念、字符串操作、排序逻辑', '\"掌握列置换密码加解密\"', '[{\"title\": \"矩阵存储\", \"description\": \"明文按行写入二维矩阵\"}, {\"title\": \"密钥控序\", \"description\": \"密钥决定列的读取顺序\"}, {\"title\": \"纯换位\", \"description\": \"不改字母仅重排位置\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (9, 628574, '希尔密码 (Hill Cipher)', '1929年提出的线性代数多字母替换密码，基于矩阵模运算加密', '古典密码学', '中等', '2小时', '基础线性代数、模运算、最大公约数', '\"掌握希尔密码加解密与原理\"', '[{\"title\": \"矩阵加密\", \"description\": \"密钥为可逆矩阵（模26）\"}, {\"title\": \"多字母替换\", \"description\": \"分组处理明文字母组\"}, {\"title\": \"代数基础\", \"description\": \"依赖线性代数与模运算\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (10, 893456, '四方密码 (Four Square Cipher)', '20世纪初提出的双字母加密，基于4个5×5矩阵，是Playfair密码的升级版', '古典密码学', '中等', '1.5小时', '基础矩阵概念、字符映射、双字母加密思想', '\"掌握四方密码加解密与矩阵构建\"', '[{\"title\": \"四阵结构\", \"description\": \"含2个标准阵+2个密钥阵\"}, {\"title\": \"双字母加密\", \"description\": \"逐对处理明文字母组\"}, {\"title\": \"坐标交叉\", \"description\": \"通过矩阵坐标交叉映射\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (11, 739285, '数字水印综述', '涵盖扩频水印嵌入提取、强度优化、擦除还原及实用工具与实验', '数字水印', '中等', '3小时', '基础图像处理、概率统计、线性代数', '\"掌握数字水印核心技术与应用\"', '[{\"title\": \"扩频嵌入\", \"description\": \"鲁棒性强 能量分散\"}, {\"title\": \"强度优化\", \"description\": \"平衡正确率与失真\"}, {\"title\": \"擦除还原\", \"description\": \"已知未知水印处理\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (12, 897321, '频域水印系统实现（DCT+DWT）', '基于Python实现DCT和DWT频域水印，涵盖嵌入、提取及性能验证', '数字水印', '中等', '2小时', 'Python基础、NumPy、图像处理基础、DCT/DWT变换概念', '\"掌握频域水印核心实现流程\"', '[{\"title\": \"DCT水印\", \"description\": \"块处理 中频嵌入\"}, {\"title\": \"DWT水印\", \"description\": \"多分辨率 低频嵌入\"}, {\"title\": \"频域鲁棒\", \"description\": \"抗压缩 抗噪声\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (13, 951472, '数字水印工具包：综合应用与完整流程', '整合扩频水印核心功能，提供测试图像生成、水印图案创建、嵌入提取、可视化分析及报告生成的一站式工具包', '数字水印', '中等', '3小时', 'Python基础、NumPy、Matplotlib、PIL图像处理、基础数字水印概念', '\"掌握综合水印工具包的使用与扩展，实现从测试数据生成到结果分析的全流程\"', '[{\"title\": \"一站式工具\", \"description\": \"集成测试图像生成、水印创建、嵌入提取、可视化、报告生成\"}, {\"title\": \"多模式支持\", \"description\": \"多种图像/水印图案模式可选，适配不同测试场景\"}, {\"title\": \"可视化分析\", \"description\": \"水印流程可视化、强度性能分析图表，直观展示效果\"}, {\"title\": \"自动化报告\", \"description\": \"生成标准化测试报告，便于结果归档与对比\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (14, 739281, '密钥管理协议设计与实现', '涵盖DH/ECDH/KDC/STS协议，详解原理、设计与Python实现', '密码协议设计专项', '中等', '4小时', 'Python基础、密码学基础、离散对数概念', '\"掌握密钥管理协议设计实现\"', '[{\"title\": \"协议全覆盖\", \"description\": \"包含交换/分发/协商三类协议\"}, {\"title\": \"原理详解\", \"description\": \"数学基础与安全依赖清晰解析\"}, {\"title\": \"实战实现\", \"description\": \"Python完整代码可直接运行验证\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (15, 851472, '认证协议设计与实现', '涵盖挑战响应、Kerberos、OAuth协议，详解原理与Python实现', '密码协议设计专项', '中等', '4小时', 'Python基础、密码学基础、对称/非对称加密概念', '\"掌握主流认证协议设计实现\"', '[{\"title\": \"协议全覆盖\", \"description\": \"实体/身份/相互认证三类协议\"}, {\"title\": \"原理透彻\", \"description\": \"安全机制与数学核心清晰解析\"}, {\"title\": \"实战导向\", \"description\": \"Python完整实现可直接验证\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (16, 872459, '五种主流签名协议原理与实现', '详解群签名、环签名等五种签名协议的原理、数学核心，提供Python实现与场景演示', '密码协议设计专项', '中等', '4小时', 'Python基础、公钥密码学基础、RSA算法原理', '\"掌握五种签名协议的应用与实现\"', '[{\"title\": \"协议全面 覆盖主流\", \"description\": \"包含群、环、盲等五种核心协议\"}, {\"title\": \"原理代码 结合紧密\", \"description\": \"理论推导与工程实现一一对应\"}, {\"title\": \"场景驱动 演示直观\", \"description\": \"模拟真实场景验证协议效果\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (17, 593721, '承诺协议与隐私保护', '详解比特承诺、PSI等五大隐私协议原理，结合Python实现与场景演示，覆盖核心隐私保护技术', '密码协议设计专项', '中等', '4.5小时', 'Python基础、哈希函数原理、离散对数基础、基础密码学概念', '\"掌握隐私协议设计与应用\"', '[{\"title\": \"协议核心 隐私导向\", \"description\": \"聚焦承诺与隐私保护核心场景\"}, {\"title\": \"原理实现 深度结合\", \"description\": \"数学原理与代码实现一一对应\"}, {\"title\": \"场景丰富 演示直观\", \"description\": \"覆盖通信、数据共享等多场景\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (18, 593722, '区块链核心共识协议', '深度解析PoW、PoS、PBFT三大主流共识协议的数学机制，结合Python完整实现与场景演示，掌握区块链共识核心技术', '区块链安全专项', '中等偏上', '5小时', 'Python基础、哈希函数原理、分布式系统基础、拜占庭容错概念、区块链基本结构', '[\"理解区块链共识协议的核心目标（一致性、最终性、活性、容错性）\", \"掌握PoW、PoS、PBFT的数学原理与工作流程\", \"能够独立实现三大共识协议的核心逻辑\", \"理解不同共识协议的适用场景与权衡取舍\"]', '[{\"title\": \"数学原理 深度拆解\", \"description\": \"从拜占庭容错理论出发，详解各协议的数学模型与安全假设\"}, {\"title\": \"代码实现 步步可测\", \"description\": \"基于Python标准库实现完整共识流程，包含区块结构、节点交互、共识验证\", \"code_coverage\": \"100%核心流程可运行，支持单节点模拟与多节点交互\"}, {\"title\": \"场景适配 对比分析\", \"description\": \"结合公链、联盟链、私有链场景，分析协议选型要点\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (19, 593723, '数字货币核心协议', '深度解析比特币UTXO模型、以太坊账户模型的数学原理与交易结构，结合Python实现完整交易流程与ERC-20智能合约，掌握数字货币底层核心技术', '区块链安全专项', '中等偏上', '6小时', 'Python基础、哈希函数原理、椭圆曲线数字签名（ECDSA）、区块链基础结构、共识协议概念', '[\"理解数字货币两大核心模型（UTXO/账户模型）的设计思想与数学原理\"]', '[{\"title\": \"双模型 深度对比\", \"description\": \"从数学定义、状态存储、交易逻辑三维度解析UTXO与账户模型的差异与适用场景\"}, {\"title\": \"代码实现 全流程覆盖\", \"description\": \"基于Python+cryptography库实现交易创建、签名验证、余额计算、智能合约执行全流程，无黑盒封装\", \"code_coverage\": \"100%核心逻辑可运行，包含钱包、交易、合约三大核心组件\"}, {\"title\": \"场景化 实战演示\", \"description\": \"模拟真实转账场景（Alice→Bob）、智能合约部署与代币交互，贴合实际应用场景\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (20, 593724, '智能合约安全核心漏洞与防御', '深度解析智能合约三大高危漏洞（重入攻击、整数溢出、访问控制）的攻击原理、历史事件与数学机制，通过Python实现漏洞复现与防御方案，掌握智能合约安全开发核心技能', '区块链安全专项', '中等偏上', '4小时', 'Solidity基础、智能合约工作原理、以太坊虚拟机（EVM）执行机制、区块链交易模型', '[\"理解智能合约三大高危漏洞的攻击原理、历史影响与数学本质\"]', '[{\"title\": \"漏洞复现\", \"description\": \"从漏洞原理→攻击流程→防御方案三维度，完整复现三大高危漏洞，每个漏洞均包含“有漏洞合约+攻击演示+安全合约”的闭环\"}, {\"title\": \"数学本质\", \"description\": \"用数学公式抽象攻击逻辑（如重入攻击的递归调用模型、整数溢出的模运算机制），深入理解漏洞底层原理\"}, {\"title\": \"实战导向\", \"description\": \"基于真实历史事件（DAO攻击、BatchOverflow、Parity黑客事件）设计演示场景，贴合实际攻击场景\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (21, 857291, '跨链协议（Cross-Chain Protocols）', '解决区块链孤岛问题，实现多链资产转移、消息传递与状态验证的协议体系', '密码协议设计专项', '中等', '8小时', '区块链基础、哈希函数、数字签名、Merkle树、智能合约入门', '\"掌握跨链核心机制与实现\"', '[{\"title\": \"多链互通\", \"description\": \"突破区块链孤岛，实现跨链协作\"}, {\"title\": \"加密验证\", \"description\": \"基于哈希与签名保障跨链安全\"}, {\"title\": \"原子约束\", \"description\": \"通过时间锁/哈希锁确保原子性\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (37, 628947, 'SHA-1 安全散列算法', 'NSA设计的160位散列算法，曾广泛应用，现因碰撞漏洞被SHA-2/3取代', '现代密码学', '中等', '3小时', '基础密码学概念、二进制运算、模运算', '\"掌握SHA-1原理与特性\"', '[{\"title\": \"固定输出 固定输出\", \"description\": \"生成160位标准摘要\"}, {\"title\": \"迭代压缩\", \"description\": \"采用Merkle–Damgård结构\"}, {\"title\": \"已被攻破\", \"description\": \"存在实际碰撞攻击实例\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (38, 879456, 'SHA-1 安全散列算法', 'SHA-1是160位哈希算法，曾广泛应用，后因碰撞漏洞被SHA-2/3取代', '现代密码学', '中等', '3小时', '基础哈希函数概念、二进制运算、模运算', '\"掌握SHA-1原理与实现\"', '[{\"title\": \"固定输出 160位\", \"description\": \"输出长度固定为160比特\"}, {\"title\": \"迭代压缩\", \"description\": \"采用迭代压缩函数结构\"}, {\"title\": \"已被攻破 无安全性\", \"description\": \"存在碰撞漏洞已被淘汰\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (39, 785943, 'MD5 消息摘要算法第五版', 'MD5是128位哈希函数，曾广泛应用，因碰撞漏洞已被淘汰仅非安全场景使用', '现代密码学', '中等', '2.5小时', '基础哈希概念、二进制运算、模运算、布尔函数', '\"掌握MD5原理与实现\"', '[{\"title\": \"固定输出 128位\", \"description\": \"输出长度固定为128比特\"}, {\"title\": \"64轮迭代 非线性\", \"description\": \"64轮迭代含四种布尔函数\"}, {\"title\": \"已被攻破 无安全性\", \"description\": \"存在快速碰撞攻击漏洞\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (40, 958721, 'SM3（国家商用密码杂凑算法）', 'SM3是中国自主设计的256位哈希算法，安全可控，广泛用于国密体系', '现代密码学', '中等', '3小时', 'SHA-256基础、二进制运算、模运算、布尔函数、循环移位', '\"掌握SM3原理与实现\"', '[{\"title\": \"自主可控 国密标准\", \"description\": \"中国自主设计的哈希算法\"}, {\"title\": \"256位输出 高安全性\", \"description\": \"输出256位摘要无有效攻击\"}, {\"title\": \"64轮迭代 抗差分\", \"description\": \"64轮迭代增强抗攻击能力\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (41, 874592, 'MD5碰撞攻击', 'MD5碰撞攻击由王小云教授2004年发现，将MD5碰撞复杂度从2^64降至2^39，彻底颠覆其安全性，本文详解其原理、实现与防护', '现代密码学', '高级', '4小时', 'MD5算法基础、差分密码分析、布尔函数、模运算、哈希函数安全性', '\"掌握MD5碰撞攻击的原理、实现方法及防护策略\"', '[{\"title\": \"差分分析 核心突破\", \"description\": \"基于差分密码分析的碰撞攻击方法\"}, {\"title\": \"复杂度骤降 2^39\", \"description\": \"碰撞复杂度从2^64降至2^39可实际实现\"}, {\"title\": \"真实碰撞 可验证\", \"description\": \"提供王小云真实碰撞对的验证实现\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (42, 873492, 'AES高级加密标准原理与实现', '详解AES加密背景、数学原理、Python实现及加解密应用', '现代密码学', '中等', '3小时', '基础编程知识、二进制与异或运算、有限域基础概念', '\"掌握AES核心原理与实现\"', '[{\"title\": \"结构清晰\", \"description\": \"SPN架构，步骤化加密流程\"}, {\"title\": \"安全高效\", \"description\": \"多密钥长度，抗攻击性能优\"}, {\"title\": \"实操性强\", \"description\": \"Python原生实现，可直接运行\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (43, 789541, 'SM4商用密码算法原理与实现', '详解SM4国产加密算法背景、数学原理、Python实现及加解密应用', '现代密码学', '中等', '3小时', '基础编程知识、二进制运算、Feistel网络基础概念', '\"掌握SM4核心原理与实现\"', '[{\"title\": \"国产自主\", \"description\": \"中国自主设计，替代国外算法\"}, {\"title\": \"Feistel结构\", \"description\": \"32轮迭代，解密仅逆序密钥\"}, {\"title\": \"多模式支持\", \"description\": \"支持ECB/CBC等加密模式\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (44, 568974, 'ECB电子密码本模式原理与实现', '详解ECB分组密码模式的原理、特性、安全问题及Python实现', '现代密码学', '简单', '1.5小时', '基础分组密码概念、PKCS#7填充、AES/SM4基础', '\"掌握ECB模式核心原理\"', '[{\"title\": \"独立加密\", \"description\": \"明文分组独立加密解密\"}, {\"title\": \"无需IV No IV\", \"description\": \"不依赖初始化向量\"}, {\"title\": \"确定性\", \"description\": \"相同明文对应相同密文\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (45, 897542, 'CBC密码分组链接模式原理与实现', '详解CBC分组密码模式的原理、特性、安全优势及Python实现', '现代密码学', '中等', '2小时', 'ECB模式基础、分组密码概念、异或运算、PKCS#7填充', '\"掌握CBC模式核心原理\"', '[{\"title\": \"链式加密\", \"description\": \"分组间通过异或形成链接\"}, {\"title\": \"需要IV Require IV\", \"description\": \"依赖随机初始化向量\"}, {\"title\": \"语义安全\", \"description\": \"相同明文产生不同密文\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (46, 748956, 'CFB密文反馈模式原理与实现', '详解CFB分组密码模式的原理、特性、安全优势及Python实现', '现代密码学', '中等', '2小时', 'CBC模式基础、分组/流密码概念、异或运算、IV使用规范', '\"掌握CFB模式核心原理\"', '[{\"title\": \"密文反馈\", \"description\": \"用密文作为加密反馈值\"}, {\"title\": \"流式加密\", \"description\": \"分组密码模拟流密码使用\"}, {\"title\": \"自同步\", \"description\": \"错误后可自动恢复同步\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (47, 748956, 'CFB密文反馈模式原理与实现', '详解CFB分组密码模式的原理、特性、安全优势及Python实现', '现代密码学', '中等', '2小时', 'CBC模式基础、分组/流密码概念、异或运算、IV使用规范', '\"掌握CFB模式核心原理\"', '[{\"title\": \"密文反馈\", \"description\": \"用密文作为加密反馈值\"}, {\"title\": \"流式加密\", \"description\": \"分组密码模拟流密码使用\"}, {\"title\": \"自同步\", \"description\": \"错误后可自动恢复同步\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (48, 958742, 'OFB输出反馈模式原理与实现', '详解OFB分组密码模式的原理、特性、安全优势及Python实现', '现代密码学', '中等', '2小时', 'CFB模式基础、流密码概念、异或运算、IV使用规范', '\"掌握OFB模式核心原理\"', '[{\"title\": \"密钥流生成\", \"description\": \"独立生成伪随机密钥流\"}, {\"title\": \"无错传播\", \"description\": \"单个错误仅影响对应位\"}, {\"title\": \"流密码特性\", \"description\": \"纯流密码工作方式\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (49, 875942, 'CTR计数器模式原理与实现', '详解CTR分组密码模式的原理、特性、安全优势及Python实现', '现代密码学', '中等', '2小时', 'OFB/CFB模式基础、流密码概念、计数器操作、Nonce使用规范', '\"掌握CTR模式核心原理\"', '[{\"title\": \"并行处理\", \"description\": \"加解密全流程可并行执行\"}, {\"title\": \"随机访问\", \"description\": \"支持任意位置数据解密\"}, {\"title\": \"Nonce依赖\", \"description\": \"依赖唯一计数器初始值\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (50, 987543, 'GCM伽罗华计数器模式原理与实现', '详解GCM认证加密模式的原理、特性、安全优势及Python实现，涵盖CTR加密与Galois域认证核心逻辑', '现代密码学', '进阶', '3小时', 'CTR模式基础、伽罗华域GF(2^128)概念、认证加密AEAD、Nonce使用规范', '\"掌握GCM模式的认证加密核心原理与实现\"', '[{\"title\": \"认证加密\", \"description\": \"同时提供机密性和完整性认证\"}, {\"title\": \"并行处理\", \"description\": \"加密和认证均可并行执行\"}, {\"title\": \"AAD支持\", \"description\": \"支持附加认证数据验证\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (51, 763291, 'RSA公钥密码算法原理与实现', '详解RSA算法的数学原理、密钥生成、加解密及数字签名实现', '现代密码学', '中等', '4小时', '数论基础、模运算、素数概念、哈希函数基础', '\"掌握RSA核心原理与实现\"', '[{\"title\": \"非对称加密\", \"description\": \"公钥加密私钥解密\"}, {\"title\": \"数字签名\", \"description\": \"私钥签名公钥验证\"}, {\"title\": \"因数分解\", \"difficulty\": \"基于大整数分解困难性\"}]', 'PUBLISHED', NULL, NULL, NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14');
INSERT INTO `learning_item` VALUES (53, 919911767, 'Prompt Engineering — 大模型 API 调用与提示词设计', '从 Transformer 架构与 token 的基本概念出发，系统讲解大语言模型的 API 调用方式。深入剖析 System Prompt 的设计方法论，涵盖 Zero-shot、Few-shot 等提示策略，掌握 temperature/top_p 等采样参数对输出行为的调控原理，最终实现用结构化提示词精确控制模型输出。', '智能体', '简单', '3小时', 'Python 基础语法（函数、字典、列表）、了解 HTTP 请求的基本概念', '[\"理解 Transformer 架构中 token 的概念与文本 tokenize 的过程\", \"掌握 chat completions 接口中各参数的含义、取值范围与调优方法\", \"理解 system/user/assistant 三种消息角色的设计意图与协作机制\", \"掌握 System Prompt 的四要素设计法与 Few-shot 提示技巧\", \"能够设计提示词方案让模型稳定输出 JSON、Markdown 等结构化格式\", \"理解 API 响应结构并实现基本的错误处理\"]', '[{\"title\": \"Token 与 API 调用\", \"description\": \"从 token 的基本概念出发，学习使用 OpenAI SDK 调用 DeepSeek API，理解请求与响应的完整数据结构。\"}, {\"title\": \"消息角色与提示策略\", \"description\": \"深入理解 system/user/assistant 三种角色的设计意图，掌握 Zero-shot、Few-shot、CoT 等提示策略的原理与适用场景。\"}, {\"title\": \"输出控制与工程实践\", \"description\": \"通过采样参数控制模型行为，学习 API 错误处理、环境变量管理等工程实践，构建可复用的调用基础设施。\"}]', 'PUBLISHED', 'item-53/template.ipynb', NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14', '2026-06-15 10:15:24');
INSERT INTO `learning_item` VALUES (54, 954905328, 'Tool Use — 让智能体具备外部工具调用能力', '从大语言模型的根本局限性出发，讲解 Function Calling 机制的设计原理与实现细节。深入理解 JSON Schema 工具定义、tool_calls 消息解析、tool 角色消息回传的完整协议，掌握单工具调用、多工具路由、并行工具调用以及工具调用错误处理的工程实践。', '智能体', '中等', '3小时', '项目一完成（掌握 API 调用与 messages 结构）、JSON 格式基础、Python 字典与列表操作', '[\"理解大模型的四类根本局限以及 Tool Use 的解决思路\", \"掌握 Function Calling 协议的完整六步流程及其背后的设计动机\", \"能够用 JSON Schema 精确定义工具的名称、描述、参数类型与约束\", \"理解 assistant（带 tool_calls）和 tool 两种新消息角色的格式要求\", \"实现单工具、多工具路由与并行工具调用的智能体\", \"掌握工具调用中的错误处理与边界情况应对\"]', '[{\"title\": \"Function Calling 协议\", \"description\": \"DeepSeek/OpenAI 提供的标准化工具调用协议。模型通过返回 tool_calls 字段表达调用意图，由系统执行后将结果回传模型，模型再据此生成最终回答。\"}, {\"title\": \"工具定义与注册\", \"description\": \"使用 JSON Schema 格式描述工具的 name、description、parameters，模型据此判断何时调用哪个工具以及传递什么参数。工具描述的质量直接决定调用的准确性。\"}, {\"title\": \"多工具路由与并行调用\", \"description\": \"通过工具注册表实现多工具路由分发，支持模型在一次回复中并行调用多个工具，以及处理工具调用中的各种异常情况。\"}]', 'PUBLISHED', 'item-54/template.ipynb', NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14', '2026-06-15 10:15:24');
INSERT INTO `learning_item` VALUES (55, 982907259, 'Memory — 让智能体记住对话上下文', '从大语言模型\'无状态\'的架构本质出发，系统讲解短期记忆的实现原理与管理策略。深入分析全量记忆、滑动窗口、摘要压缩三种方案的 token 开销与信息保留的权衡，探讨 Token 预算管理方法，以及 Memory 与 Tool Use 组合使用时的消息完整性约束。', '智能体', '高级', '3小时', '项目一完成（掌握 API 调用）、项目二完成（理解 messages 结构与 tool 消息）', '[\"从模型架构层面理解\'无状态\'的本质以及为什么需要 Memory 机制\", \"掌握通过 messages 列表维护对话上下文的核心方法与实现细节\", \"理解全量记忆、滑动窗口、摘要压缩三种策略的原理、优劣与适用场景\", \"能够估算对话的 token 消耗并设计合理的 Token 预算\", \"实现带记忆的工具调用智能体，正确处理 tool 消息的截断约束\", \"了解长期记忆的概念与实现思路\"]', '[{\"title\": \"短期记忆机制\", \"description\": \"将对话历史存储在 messages 列表中，每次调用 API 时把完整上下文一起发给模型。这是所有记忆策略的基础。\"}, {\"title\": \"记忆管理策略\", \"description\": \"滑动窗口只保留最近 N 轮，摘要压缩将早期对话总结为概要，两者结合在 token 消耗和信息保留之间取得平衡。\"}, {\"title\": \"Token 预算管理\", \"description\": \"估算对话各部分的 token 消耗，为记忆、工具描述、输出预留分别分配额度，实现可控的资源管理。\"}]', 'PUBLISHED', 'item-55/template.ipynb', NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14', '2026-06-15 10:15:24');
INSERT INTO `learning_item` VALUES (56, 994792822, 'Code Sandbox — 让智能体自己写代码、自己执行', '从 Code Interpreter 的核心原理出发，系统讲解如何让大模型生成代码、在沙箱中执行、捕获输出并返回模型。深入理解 exec() 与 eval() 的区别、io.StringIO 输出捕获机制、正则代码提取、自我修正循环的实现，以及代码执行超时控制与生产环境安全隔离方案。', '智能体', '高级', '3.5小时', '项目一完成（掌握 API 调用）、Python 基础（了解 exec/eval 概念、异常处理）', '[\"理解 Code Sandbox 的核心思想：模型写代码 → 系统执行 → 结果回传\", \"掌握 Python 的 exec() 和 io.StringIO 实现代码执行与输出捕获\", \"能够用正则表达式从模型回复中精确提取代码块\", \"实现带自我修正的代码智能体，理解错误反馈循环的工作机制\", \"掌握代码执行超时控制方法\", \"理解生产环境中代码沙箱的安全隔离要求与实现方案\"]', '[{\"title\": \"代码执行与输出捕获\", \"description\": \"使用 exec() 执行字符串代码，通过 io.StringIO 重定向 sys.stdout 来捕获 print 输出，实现代码执行结果的程序化获取。\"}, {\"title\": \"代码提取与格式化\", \"description\": \"使用正则表达式从模型返回的自然语言+代码混合内容中精确提取代码块，处理多种格式变体。\"}, {\"title\": \"自我修正与安全隔离\", \"description\": \"当代码执行出错时将错误信息返回给模型进行修正，同时理解生产环境中沙箱隔离的必要性。\"}]', 'PUBLISHED', 'item-56/template.ipynb', NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14', '2026-06-15 10:15:24');
INSERT INTO `learning_item` VALUES (57, 990035195, 'Multi-Agent — 多智能体分工协作系统', '从单智能体的局限性出发，讲解多智能体系统的核心思想：让多个专业 AI 角色分工合作。深入理解角色定义、消息传递、协作流程三个核心要素，系统掌握串行流水线、辩论模式、主从模式三种经典协作架构的实现方法与适用场景，探讨智能体间上下文传递设计与错误传播问题。', '智能体', '高级', '3.5小时', '项目一至四完成（掌握 Prompt、Tool Use、Memory、Code Sandbox）', '[\"理解单智能体在复杂任务中的局限性以及多智能体的优势\", \"掌握多智能体系统的三个核心要素：角色定义、消息传递、协作流程编排\", \"能够设计智能体的角色分工与 System Prompt，定义清晰的输入输出接口\", \"实现串行流水线、辩论模式、主从模式三种协作架构\", \"理解智能体间上下文传递的设计方法与错误传播问题\", \"掌握多智能体系统的设计原则与最佳实践\"]', '[{\"title\": \"角色分工机制\", \"description\": \"每个智能体有独立的身份、职责和 System Prompt，专注单一任务比\'全能选手\'更可靠。角色定义的质量直接决定协作效果。\"}, {\"title\": \"消息传递与上下文设计\", \"description\": \"智能体之间通过\'消息\'通信，一个智能体的输出作为另一个智能体的输入。上下文传递的格式设计是系统可靠性的关键。\"}, {\"title\": \"协作流程编排\", \"description\": \"定义智能体的执行顺序和数据流向，包括串行流水线、辩论模式、主从模式等多种架构及其组合。\"}]', 'PUBLISHED', 'item-57/template.ipynb', NULL, '2026-06-15 10:05:14', '2026-06-15 10:05:14', '2026-06-15 10:15:24');
